 10→interface PostCardProps {
 11→  title: string;
 12→  bodyPreview: string;
 13→  authorName: string;
 14→  authorAvatar?: string | null;
 15→  authorBadge?: 'legend' | 'og' | null;
 16→  bannerImage?: string | null;
 17→  bannerContent?: React.ReactNode;
 18→  postType?: string;
 19→  readingTime?: string;
 20→  likeCount: number;
 21→  commentCount: number;
 22→  bookmarkCount?: number;
 23→  isLiked?: boolean;
 24→  isBookmarked?: boolean;
 25→  userReaction?: string | null;
 26→  onPress?: () => void;
 27→  onLike?: () => void;
 28→  onComment?: () => void;
 29→  onBookmark?: () => void;
 30→  onRepost?: () => void;
 31→  onReact?: (type: string) => void;
 32→  onAuthorPress?: () => void;
