 42→export function PostCard({
 43→  title,
 44→  bodyPreview,
 45→  authorName,
 46→  authorAvatar,
 47→  authorBadge,
 48→  bannerImage,
 49→  bannerContent,
 50→  postType,
 51→  readingTime,
 52→  likeCount,
 53→  commentCount,
 54→  bookmarkCount,
 55→  isLiked,
 56→  isBookmarked,
 57→  userReaction,
 58→  onPress,
 59→  onLike,
 60→  onComment,
 61→  onBookmark,
 62→  onRepost,
 63→  onReact,
 64→  onAuthorPress,
 65→  isRepost,
 66→  repostCaption,
 67→  repostSourceTitle,
 68→  repostSourcePreview,
 69→  repostSourceAuthorName,
 70→  repostSourceAuthorAvatar,
 71→  onEmbeddedPress,
 72→}: PostCardProps) {
 73→  const {colors} = useTheme();
 74→  const s = shadows(colors);
 75→
 76→  const hasSource = !!(repostSourceTitle || repostSourcePreview || repostSourceAuthorName);
 77→
 78→  return (
 79→    <Pressable
 80→      onPress={onPress}
 81→      style={({pressed}) => [
 82→        styles.card,
 83→        {
 84→          backgroundColor: colors.bgCard,
 85→          borderColor: colors.borderCard,
 86→        },
 87→        s.card,
 88→        pressed && styles.pressed,
 89→      ]}>
 90→      {isRepost ? (
 91→        <>
 92→          {/* Repost badge header */}
 93→          <View style={styles.repostBadge}>
 94→            <RepostIcon size={14} color={colors.textFaint} />
 95→            <Text style={[styles.repostBadgeText, {color: colors.textFaint}]}>
 96→              <Text style={[styles.repostBadgeName, {color: colors.textSecondary}]}>
 97→                {authorName}
 98→              </Text>
 99→              {' reposted'}
100→            </Text>
101→          </View>
102→
103→          <View style={styles.content}>
104→            {/* Repost caption */}
105→            {repostCaption ? (
106→              <Text style={[styles.repostCaption, {color: colors.textBody}]}>
107→                {repostCaption}
108→              </Text>
109→            ) : null}
110→
111→            {/* Embedded original post card */}
112→            {hasSource ? (
113→              <Pressable
114→                onPress={onEmbeddedPress}
115→                style={[
116→                  styles.embeddedCard,
117→                  {borderColor: colors.borderCard, backgroundColor: colors.bgPrimary},
118→                ]}>
119→                <View style={styles.embeddedAuthorRow}>
120→                  <Avatar
121→                    uri={repostSourceAuthorAvatar}
122→                    name={repostSourceAuthorName ?? ''}
123→                    size={20}
124→                  />
125→                  <Text
126→                    style={[styles.embeddedAuthorName, {color: colors.textSecondary}]}
127→                    numberOfLines={1}>
128→                    {repostSourceAuthorName}
129→                  </Text>
130→                </View>
131→                {repostSourceTitle ? (
132→                  <Text
133→                    style={[styles.embeddedTitle, {color: colors.textHeading}]}
134→                    numberOfLines={2}>
135→                    {repostSourceTitle}
136→                  </Text>
137→                ) : null}
138→                {repostSourcePreview ? (
139→                  <Text
140→                    style={[styles.embeddedPreview, {color: colors.textBody}]}
141→                    numberOfLines={3}>
142→                    {repostSourcePreview}
143→                  </Text>
144→                ) : null}
145→              </Pressable>
146→            ) : (
147→              <View
148→                style={[
149→                  styles.embeddedCard,
150→                  {borderColor: colors.borderCard, backgroundColor: colors.bgPrimary},
151→                ]}>
152→                <Text style={[styles.repostUnavailable, {color: colors.textFaint}]}>
153→                  This post is no longer available
154→                </Text>
155→              </View>
156→            )}
157→          </View>
158→        </>
159→      ) : (
160→        <>
161→          {bannerContent ?? (bannerImage ? (
162→            <Image
163→              source={{uri: bannerImage}}
164→              style={styles.banner}
165→              resizeMode="cover"
166→            />
167→          ) : null)}
168→
169→          <View style={styles.content}>
170→            {/* Author row */}
171→            <View style={styles.authorRow}>
172→              <Pressable
173→                style={styles.authorTouchable}
174→                onPress={onAuthorPress}
175→                disabled={!onAuthorPress}>
176→                <Avatar uri={authorAvatar} name={authorName} size={22} badge={authorBadge} />
177→                <Text
178→                  style={[styles.authorName, {color: colors.textSecondary}]}
179→                  numberOfLines={1}>
180→                  {authorName}
181→                </Text>
182→                {authorBadge ? <BadgeCheckIcon size={14} badge={authorBadge} /> : null}
183→              </Pressable>
184→              {postType && postType !== 'journal' ? (
185→                <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
186→                  <Text style={[styles.typeText, {color: colors.accentSage}]}>
187→                    {postType}
188→                  </Text>
189→                </View>
190→              ) : null}
191→              {readingTime ? (
192→                <View style={[styles.typePill, {backgroundColor: colors.bgPill}]}>
193→                  <Text style={[styles.typeText, {color: colors.accentSage}]}>
194→                    {readingTime}
195→                  </Text>
196→                </View>
197→              ) : null}
198→            </View>
199→
200→            {/* Title */}
201→            <Text
202→              style={[styles.title, {color: colors.textHeading}]}
203→              numberOfLines={2}>
204→              {title}
205→            </Text>
206→
207→            {/* Body preview */}
208→            {bodyPreview ? (
209→              <Text
210→                style={[styles.body, {color: colors.textBody}]}
211→                numberOfLines={3}>
212→                {bodyPreview}
213→              </Text>
214→            ) : null}
215→          </View>
216→        </>
217→      )}
218→
219→      <ActionBar
220→        likeCount={likeCount}
221→        commentCount={commentCount}
222→        bookmarkCount={bookmarkCount}
223→        isLiked={isLiked}
224→        isBookmarked={isBookmarked}
225→        userReaction={userReaction}
226→        onLike={onLike}
227→        onComment={onComment}
228→        onBookmark={onBookmark}
229→        onRepost={onRepost}
230→        onReact={onReact}
231→      />
232→    </Pressable>
233→  );
234→}
